## 2️⃣ `blocksci_stubs.cpp` – C/​C++ glue

```cpp
/*-----------------------------------------------------------------
   blocksci_stubs.cpp  –  OCaml <-> BlockSci binding
   -------------------------------------------------
   Compile with a C++ compiler (g++/clang++) and link the resulting
   object file with the OCaml runtime (ocamlc -custom ...).

   The stub expects the following BlockSci symbols to be available:

     class Block {
       public:
         int    height() const;
         std::string hash() const;          // hex string
         double timestamp() const;          // Unix time (seconds)
     };

     class BlockIterator {
       public:
         bool   has_next() const;
         Block* next();                      // ownership transferred
         ~BlockIterator();
     };

     BlockIterator* get_block_iterator();   // returns a fresh iterator

   Adjust the #include lines below to point to the real BlockSci headers.
-----------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <string>
#include <cstring>
#include <iostream>   // for debugging only (remove in prod)

// ------------------------------------------------------------------
// 1.  Include the real BlockSci headers (replace the path as needed)
// ------------------------------------------------------------------
#include "blocksci/block.hpp"          // <-- your BlockSci header
#include "blocksci/iterator.hpp"       // <-- your iterator header

// ------------------------------------------------------------------
// 2.  Helpers to convert between OCaml values and C++ pointers
// ------------------------------------------------------------------

/* The custom operations structure for the abstract type `block`. */
static void block_finalize(value v) {
  Block* b = *(Block**)Data_custom_val(v);
  delete b;                     // free the C++ object when GC'd
}

static struct custom_operations block_ops = {
  "org.blocksci.block",          // identifier – must be unique
  block_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

/* Wrap a freshly‑allocated Block* into an OCaml custom value. */
static value caml_wrap_block(Block* b) {
  value v = caml_alloc_custom(&block_ops, sizeof(Block*), 0, 1);
  Block** pv = (Block**)Data_custom_val(v);
  *pv = b;
  return v;
}

/* Extract the raw Block* from an OCaml `block` value. */
static Block* Block_val(value v) {
  return *(Block**)Data_custom_val(v);
}

/*-----------------------------------------------------------------
   3.  Accessor functions exposed to OCaml
-----------------------------------------------------------------*/

extern "C" CAMLprim value caml_block_height(value v_block) {
  CAMLparam1(v_block);
  Block* b = Block_val(v_block);
  int h = b->height();
  CAMLreturn(Val_int(h));
}

extern "C" CAMLprim value caml_block_hash(value v_block) {
  CAMLparam1(v_block);
  Block* b = Block_val(v_block);
  const std::string& h = b->hash();        // already hex
  CAMLreturn(caml_copy_string(h.c_str()));
}

extern "C" CAMLprim value caml_block_timestamp(value v_block) {
  CAMLparam1(v_block);
  Block* b = Block_val(v_block);
  double ts = b->timestamp();
  CAMLreturn(caml_copy_double(ts));
}

/*-----------------------------------------------------------------
   4.  The iterator driver
-----------------------------------------------------------------*/

extern "C" CAMLprim value caml_iter_blocks(value v_cb) {
  CAMLparam1(v_cb);
  CAMLlocal1(v_block);          // temporary OCaml value for each block

  /* 4.1 Obtain a fresh iterator from BlockSci */
  BlockIterator* it = get_block_iterator();
  if (!it) caml_failwith("Blocksci: failed to get block iterator");

  /* 4.2 Walk the iterator, invoking the OCaml callback for each block */
  while (it->has_next()) {
    Block* raw = it->next();               // ownership transferred to us
    if (!raw) continue;                    // defensive

    v_block = caml_wrap_block(raw);        // now an OCaml value

    /* Call the user supplied OCaml function.  Use _exn() to propagate
       any exception out of the loop.                                            */
    value result = caml_callback_exn(v_cb, v_block);
    if (Is_exception_result(result)) {
      /* Clean up the iterator before re‑raising the exception. */
      delete it;
      caml_raise(result);
    }
    /* The block value will be freed automatically by the GC (finalizer). */
  }

  delete it;                               // iterator is no longer needed
  CAMLreturn(Val_unit);
}

/*-----------------------------------------------------------------
   5.  Registration table (optional, but nice for ocamlc -custom)
-----------------------------------------------------------------*/

static struct caml_named_value {
  const char* name;
  value (*fn) (value);
} caml_named_values[] = {
  { "Blocksci.block_height",      caml_block_height },
  { "Blocksci.block_hash",        caml_block_hash },
  { "Blocksci.block_timestamp",   caml_block_timestamp },
  { "Blocksci.iter_blocks",       caml_iter_blocks },
  { nullptr, nullptr }
};

extern "C" void caml_register_named_values(void) {
  for (int i = 0; caml_named_values[i].name != nullptr; ++i)
    caml_register_named_value(caml_named_values[i].name, caml_named_values[i].fn);
}
```

### How the stub works

| OCaml side                              | C++ side (stub)                                   |
|----------------------------------------|---------------------------------------------------|
| `type block` (abstract)                | a custom value that stores a `Block*` pointer.   |
| `block_height b` → C++ `b->height()`   | `caml_block_height` extracts the pointer and returns an `int`. |
| `block_hash b` → C++ `b->hash()`       | `caml_block_hash` copies the C++ string into an OCaml string. |
| `block_timestamp b` → C++ `b->timestamp()` | `caml_block_timestamp` returns a float. |
| `iter_blocks f` → iterator loop        | `caml_iter_blocks` obtains a `BlockIterator*`, loops, builds a `block` value for each `Block*` and calls the OCaml closure with `caml_callback_exn`.  Exceptions stop the iteration and are re‑raised. |
| GC finalizer (`block_finalize`)        | `delete b` frees the C++ `Block` when the OCaml value is collected. |

All memory management is deterministic:

* The iterator (`BlockIterator*`) is created at the start of `iter_blocks` and destroyed at the end.
* Each `Block*` returned by the iterator is wrapped in a custom OCaml value; its finalizer frees the C++ object when the OCaml value is no longer reachable.
* If the user stores a block in a data structure, the block lives as long as that OCaml value does; otherwise it is reclaimed automatically after the callback returns.

